SELECT EXISTS(
    SELECT 1
    FROM users
    WHERE email = #{email}
      AND deleted_at IS NULL
)

SELECT EXISTS(
    SELECT 1
    FROM users
    WHERE nickname = #{nickname}
      AND deleted_at IS NULL
)

SELECT EXISTS(
  SELECT 1
  FROM users
  WHERE user_id = #{userId}
    AND deleted_at IS NULL
)
